354	// downloadAndExtract downloads a .tar.gz from url into destDir and returns
355	// the path of the single top-level directory extracted from the archive.
356	func downloadAndExtract(url, destDir string) (string, error) {
357		resp, err := http.Get(url) //nolint:noctx
358		if err != nil {
359			return "", fmt.Errorf("fetching %s: %w", url, err)
360		}
361		defer func() { _ = resp.Body.Close() }()
362	
363		if resp.StatusCode != http.StatusOK {
364			return "", fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
365		}
366	
367		gz, err := gzip.NewReader(resp.Body)
368		if err != nil {
369			return "", fmt.Errorf("reading gzip: %w", err)
370		}
371		defer func() { _ = gz.Close() }()
372	
373		tr := tar.NewReader(gz)
374		var topDir string
375	
376		for {
377			hdr, err := tr.Next()
378			if err == io.EOF {
379				break
380			}
381			if err != nil {
382				return "", fmt.Errorf("reading tar: %w", err)
383			}
384	
385			// Sanitize path to prevent directory traversal.
386			clean := filepath.Clean(hdr.Name)
387			if strings.HasPrefix(clean, "..") {
388				continue
389			}
390	
391			dest := filepath.Join(destDir, clean)
392	
393			// Skip PAX global headers (GitHub tarballs include these).
394			if hdr.Typeflag == tar.TypeXGlobalHeader {
395				continue
396			}
397	
398			// Track the top-level directory name.
399			parts := strings.SplitN(clean, string(filepath.Separator), 2)
400			if topDir == "" && parts[0] != "" && parts[0] != "." {
401				topDir = parts[0]
402			}
403	
404			switch hdr.Typeflag {
405			case tar.TypeDir:
406				if err := os.MkdirAll(dest, 0755); err != nil {
407					return "", err
408				}
409			case tar.TypeReg:
410				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
411					return "", err
412				}
413				f, err := os.OpenFile(dest, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, hdr.FileInfo().Mode())
414				if err != nil {
415					return "", err
416				}
417				if _, err := io.Copy(f, tr); err != nil {
418					_ = f.Close()
419					return "", err
420				}
421				_ = f.Close()
422			case tar.TypeSymlink:
423				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
424					return "", err
425				}
426				_ = os.Remove(dest)
427				if err := os.Symlink(hdr.Linkname, dest); err != nil {
428					return "", err
429				}
430			}
431		}
432	
433		if topDir == "" {
434			return destDir, nil
435		}
436		return filepath.Join(destDir, topDir), nil
437	}
