439	// CopyScriptFromRoot copies a script from an installed plugin root to the
440	// target path. Exported for use by local install path.
441	func CopyScriptFromRoot(installedRoot string, mapping *InstallMapping) (string, error) {
442		files, err := copyMapping(installedRoot, mapping)
443		if err != nil {
444			return "", err
445		}
446		dst := ExpandHome(mapping.Target)
447		if info, err := os.Stat(dst); err == nil && !info.IsDir() {
448			_ = os.Chmod(dst, info.Mode()|0111)
449		}
450		if len(files) > 0 {
451			return files[0], nil
452		}
453		return dst, nil
