456	// copyMapping copies files from srcDir/<mapping.Source> to ExpandHome(mapping.Target).
457	// If the source is a single file and the target does not end with a path
458	// separator, the target is treated as the exact destination file path.
459	// If the source is a directory (or target ends with /), files are copied
460	// into the target directory.
461	// Returns the list of destination files written.
462	func copyMapping(srcDir string, mapping *InstallMapping) ([]string, error) {
463		src := filepath.Join(srcDir, filepath.FromSlash(mapping.Source))
464		dst := ExpandHome(mapping.Target)
465	
466		info, err := os.Stat(src)
467		if os.IsNotExist(err) {
468			// Source path doesn't exist in this repo — skip silently.
469			return nil, nil
470		}
471		if err != nil {
472			return nil, err
473		}
474	
475		var written []string
476	
477		if info.IsDir() {
478			// If dst is an existing symlink (e.g. from a prior --local install),
479			// remove it before creating the real directory.
480			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
481				if err := os.Remove(dst); err != nil {
482					return nil, fmt.Errorf("removing symlink at %s: %w", dst, err)
483				}
484			}
485	
486			// Copy directory tree into dst (create dst as a directory).
487			if err := os.MkdirAll(dst, 0755); err != nil {
488				return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
489			}
490	
491			// HELIX skills use symlinks, so resolve each entry via os.Stat.
492			entries, err := os.ReadDir(src)
493			if err != nil {
494				return nil, err
495			}
496			for _, e := range entries {
497				srcPath := filepath.Join(src, e.Name())
498				dstPath := filepath.Join(dst, e.Name())
499	
500				fi, err := os.Stat(srcPath)
501				if err != nil {
502					if recovered := recoverSkillDir(srcDir, src, e.Name()); recovered != "" {
503						srcPath = recovered
504						fi, err = os.Stat(srcPath)
505					}
506					if err != nil {
507						continue // skip unrecoverable broken symlinks
508					}
509				}
510	
511				if fi.IsDir() {
512					subFiles, subErr := copyMapping(srcPath, &InstallMapping{Source: ".", Target: dstPath})
513					if subErr != nil {
514						return nil, subErr
515					}
516					written = append(written, subFiles...)
517				} else if fi.Mode().IsRegular() {
518					if err := copyFile(srcPath, dstPath); err != nil {
519						return nil, err
520					}
521					written = append(written, dstPath)
522				}
523			}
524		} else {
525			// Source is a single file. If target ends with /, copy into that
526			// directory using the source filename; otherwise treat target as
527			// the exact destination file path.
528			var dstFile string
529			if strings.HasSuffix(mapping.Target, "/") {
530				if err := os.MkdirAll(dst, 0755); err != nil {
531					return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
532				}
533				dstFile = filepath.Join(dst, filepath.Base(src))
534			} else {
535				dstFile = dst
536			}
537			if err := copyFile(src, dstFile); err != nil {
538				return nil, err
539			}
540			written = append(written, dstFile)
541		}
542	
543		return written, nil
544	}
