546	// copyFile copies src to dst, creating parent directories as needed.
547	// Preserves the source file's permissions. If dst already exists (file,
548	// symlink, or directory), it is removed first.
549	func copyFile(src, dst string) error {
550		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
551			return err
552		}
553	
554		// Remove any existing file/symlink/directory at dst.
555		if _, err := os.Lstat(dst); err == nil {
556			if err := os.RemoveAll(dst); err != nil {
557				return fmt.Errorf("removing existing %s: %w", dst, err)
558			}
559		}
560	
561		srcInfo, err := os.Stat(src)
562		if err != nil {
563			return err
564		}
565	
566		in, err := os.Open(src)
567		if err != nil {
568			return err
569		}
570		defer func() { _ = in.Close() }()
571	
572		out, err := os.OpenFile(dst, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, srcInfo.Mode())
573		if err != nil {
574			return err
575		}
576		defer func() { _ = out.Close() }()
577	
578		_, err = io.Copy(out, in)
579		return err
580	}
