582	// downloadFile fetches url and writes it to dest.
583	func downloadFile(url, dest string) error {
584		resp, err := http.Get(url) //nolint:noctx
585		if err != nil {
586			return fmt.Errorf("fetching %s: %w", url, err)
587		}
588		defer func() { _ = resp.Body.Close() }()
589	
590		if resp.StatusCode != http.StatusOK {
591			return fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
592		}
593	
594		f, err := os.Create(dest)
595		if err != nil {
596			return err
597		}
