27	type packageManifestRaw struct {
28		Name        string         `yaml:"name"`
29		Version     string         `yaml:"version"`
30		Description string         `yaml:"description"`
31		Type        string         `yaml:"type"`
32		Source      string         `yaml:"source"`
33		APIVersion  any            `yaml:"api_version"`
