38	// knownManifestKeys is the set of top-level keys consumed by the current
39	// manifest schema. Any additional keys are preserved on Package.Extra so
40	// manifests written against newer api_versions round-trip without silent
41	// field loss.
42	var knownManifestKeys = map[string]struct{}{
43		"name":        {},
44		"version":     {},
45		"description": {},
46		"type":        {},
47		"source":      {},
48		"api_version": {},
49		"install":     {},
